{
  "sentences": [
    {
      "text": "我肚子餓，所以想吃飯。",
      "pinyin": "Wǒ dùzi è, suǒyǐ xiǎng chī fàn.",
      "pinyin_numeric": "wo3 du4zi e4, suo3yi3 xiang3 chi1 fan4.",
      "translation_en": "I'm hungry, so I want to eat.",
      "translation_ko": "배가 고파서 밥을 먹고 싶어요."
    },
    {
      "text": "我口渴，所以想喝一杯水。",
      "pinyin": "Wǒ kǒukě, suǒyǐ xiǎng hē yī bēi shuǐ.",
      "pinyin_numeric": "wo3 kou3ke3, suo3yi3 xiang3 he1 yi1 bei1 shui3.",
      "translation_en": "I'm thirsty, so I want to drink a glass of water.",
      "translation_ko": "목이 말라서 물 한 잔을 마시고 싶어요."
    },
    {
      "text": "我感冒了，所以想休息。",
      "pinyin": "Wǒ gǎnmào le, suǒyǐ xiǎng xiūxí.",
      "pinyin_numeric": "wo3 gan3mao4 le0, suo3yi3 xiang3 xiu1xi2.",
      "translation_en": "I have a cold, so I want to rest.",
      "translation_ko": "감기에 걸려서 쉬고 싶어요."
    },
    {
      "text": "我太累了，所以不想去公司。",
      "pinyin": "Wǒ tài lèi le, suǒyǐ bù xiǎng qù gōngsī.",
      "pinyin_numeric": "wo3 tai4 lei4 le0, suo3yi3 bu4 xiang3 qu4 gong1si1.",
      "translation_en": "I'm too tired, so I don't want to go to the company.",
      "translation_ko": "너무 피곤해서 회사에 가고 싶지 않아요."
    },
    {
      "text": "我沒帶錢，所以不想買東西。",
      "pinyin": "Wǒ méi dài qián, suǒyǐ bù xiǎng mǎi dōngxī.",
      "pinyin_numeric": "wo3 mei2 dai4 qian2, suo3yi3 bu4 xiang3 mai3 dong1xi1.",
      "translation_en": "I didn't bring money, so I don't want to buy anything.",
      "translation_ko": "돈을 안 가져와서 물건을 사고 싶지 않아요."
    },
    {
      "text": "我想省錢，所以不想喝咖啡。",
      "pinyin": "Wǒ xiǎng shěng qián, suǒyǐ bù xiǎng hē kāfēi.",
      "pinyin_numeric": "wo3 xiang3 sheng3 qian2, suo3yi3 bu4 xiang3 he1 ka1fei1.",
      "translation_en": "I want to save money, so I don't want to drink coffee.",
      "translation_ko": "돈을 아끼고 싶어서 커피를 마시고 싶지 않아요."
    },
    {
      "text": "我剛下班，所以想回家休息。",
      "pinyin": "Wǒ gāng xiàbān, suǒyǐ xiǎng huí jiā xiūxí.",
      "pinyin_numeric": "wo3 gang1 xia4ban1, suo3yi3 xiang3 hui2 jia1 xiu1xi2.",
      "translation_en": "I just got off work, so I want to go home and rest.",
      "translation_ko": "방금 퇴근해서 집에 가서 쉬고 싶어요."
    },
    {
      "text": "我忘記帶悠遊卡，所以想用現金。",
      "pinyin": "Wǒ wàngjì dài yōuyóukǎ, suǒyǐ xiǎng yòng xiànjīn.",
      "pinyin_numeric": "wo3 wang4ji4 dai4 you1you2ka3, suo3yi3 xiang3 yong4 xian4jin1.",
      "translation_en": "I forgot to bring my EasyCard, so I want to use cash.",
      "translation_ko": "유유카드를 가져오는 걸 잊어버려서 현금을 쓰고 싶어요."
    },
    {
      "text": "我沒睡飽，所以不想吃早餐。",
      "pinyin": "Wǒ méi shuì bǎo, suǒyǐ bù xiǎng chī zǎocān.",
      "pinyin_numeric": "wo3 mei2 shui4 bao3, suo3yi3 bu4 xiang3 chi1 zao3can1.",
      "translation_en": "I didn't sleep enough, so I don't want to eat breakfast.",
      "translation_ko": "잠을 충분히 못 자서 아침을 먹고 싶지 않아요."
    },
    {
      "text": "我頭痛，所以想休息一下。",
      "pinyin": "Wǒ tóutòng, suǒyǐ xiǎng xiūxí yīxià.",
      "pinyin_numeric": "wo3 tou2tong4, suo3yi3 xiang3 xiu1xi2 yi1xia4.",
      "translation_en": "I have a headache, so I want to rest for a while.",
      "translation_ko": "머리가 아파서 잠시 쉬고 싶어요."
    }
  ]
}
